import { UPG_CORE_EDGE_TYPES } from '@upg/core'
import { UPG_EXTENDED_EDGE_MAP } from '@upg/core'

/**
 * Tiered edge type inference.
 *
 * Tier 1 — Core (25 edges from UPG open standard): always valid
 * Tier 2 — Extended (~500 edges from the extended set): will sync correctly
 * Tier 3 — Unknown: auto-generated fallback, may not sync to cloud
 */

// ── Tier 1: Core lookup ──────────────────────────────────────────────────────

const CORE_EDGE_LOOKUP = new Map<string, string>()

for (const edgeType of UPG_CORE_EDGE_TYPES) {
  // Parse "source_verb_target" patterns (has, produces, informs, addresses, pursues, relates_to)
  const match = edgeType.match(/^(\w+?)_(has|produces|informs|addresses|pursues|relates_to)_(\w+)$/)
  if (match) {
    const [, sourceType, , targetType] = match
    CORE_EDGE_LOOKUP.set(`${sourceType}:${targetType}`, edgeType)
  }
}

// ── Tier 2: Extended lookup ──────────────────────────────────────────────────

// UPG_EXTENDED_EDGE_MAP is already in 'source:target' → 'edge_type' format

// ── Inference ────────────────────────────────────────────────────────────────

export interface EdgeInferenceResult {
  edgeType: string
  tier: 'core' | 'extended' | 'unknown'
  warning?: string
}

/**
 * Infers the edge type from source and target node types.
 *
 * Returns the tier the edge was found in plus an optional warning
 * for unknown edges that may not sync to the cloud.
 */
export function inferEdgeTypeWithTier(
  sourceType: string,
  targetType: string,
): EdgeInferenceResult {
  const key = `${sourceType}:${targetType}`

  // Tier 1: Core UPG standard
  const core = CORE_EDGE_LOOKUP.get(key)
  if (core) return { edgeType: core, tier: 'core' }

  // Tier 2: Extended set
  const extended = UPG_EXTENDED_EDGE_MAP[key]
  if (extended) return { edgeType: extended, tier: 'extended' }

  // Tier 3: Unknown — fallback to _has_ with warning
  const fallback = `${sourceType}_has_${targetType}`
  return {
    edgeType: fallback,
    tier: 'unknown',
    warning: `Edge type '${fallback}' is not in the UPG standard or extended set. It will work locally but may not sync correctly to the cloud.`,
  }
}

/**
 * Simple inference — returns just the edge type string.
 * Backward-compatible with the old API.
 */
export function inferEdgeType(sourceType: string, targetType: string): string {
  return inferEdgeTypeWithTier(sourceType, targetType).edgeType
}
